"""
MKT Original Language Commentary — Job chapters 30–32
Run: python3 scripts/zc-original-job-30-32.py
Verses: ch30×31 + ch31×40 + ch32×22 = 93

Key notes:
- ch30: Job's counter-lament — the reversal of ch29's honor; v16 nep̄eš tiššāpēḵ
  echoes Ps 22:14 (poured out like water); v20 divine silence matches Ps 22:2.
- ch31: The great oath of clearance — the most comprehensive ethical code in the OT.
  v1 eye-covenant prefigures Matt 5:28; v33 'like Adam I hid' is the only unambiguous
  Adam-sin reference in OT poetry; v35 tāw (last letter) = Job's legal signature.
- ch32: Elihu's introduction — double anger against both Job and the friends. v8's
  rûaḥ/nišmaṯ Šaddai as source of understanding connects Gen 2:7 to John 20:22.
  v19's new-wineskin simile anticipates Matt 9:17.
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    return json.loads(p.read_text()) if p.exists() else {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

JOB3032 = {
  "30": {
    "1": "<p><span class='term'>wĕʿattāh śāḥăqû ʿālay</span> — 'but now those younger than me mock me' — śāḥaq (to laugh/mock, from the same root as Isaac's name) marks the exact inversion of ch29: there Job was honored by elders and princes; here he is mocked by the young of the lowest social tier. <span class='term'>ʾăšer māʾastî ʾăḇôṯām lāšîṯ ʿim-kalbê ṣōʾnî</span> — 'whose fathers I would have disdained to set with the dogs of my flock' — keleḇ (dog) in the ancient Near East was not a pet but a scavenger, a term of contempt (1 Sam 17:43; 2 Sam 9:8); guarding sheep with such men would have been below the dignity of Job's household. The social descent described is vertiginous: from revered elder (ch29) to the mockery of society's rejects.</p>",
    "2": "<p><span class='term'>gam-kōaḥ yĕḏêhem lāmmāh lî</span> — 'what use to me is the strength of their hands?' — lāmmāh lî = 'what is it to me?'; kōaḥ yāḏ = the strength/capacity of the hand. <span class='term'>ʿālêmô ʾāḇad kālaḥ</span> — 'upon them old age has perished' — kālaḥ is a rare word (only here and 5:26) meaning full age or mature strength; the phrase says that vigor has already wasted away on these men. Job's contempt is not for poverty itself but for those who lack even the minimal productive capacity that might make them members of his community.</p>",
    "3": "<p><span class='term'>bĕḥeser ûḇĕrāʿāḇ galmûḏ</span> — 'through want and famine they are barren/solitary' — galmûḏ means barren or desolate (used in Isa 49:21 of a barren woman); here applied to people who have been left without community or offspring in the wilderness of desolation. <span class='term'>hāʿōrĕqîm ṣiyyāh ʾemeš</span> — 'gnawing at waste and desolation in former times' — ṣiyyāh = drought/desolation (the wilderness noun); the image is of people driven to gnaw at desolation itself, the wilderness as the only food available.</p>",
    "4": "<p><span class='term'>haqqōṭĕpîm mallûaḥ ʿălê-śîaḥ</span> — 'those who pluck saltbush leaves from among the shrubs' — mallûaḥ is the orache or saltbush (Atriplex), an edible but unpalatable shrub; śîaḥ = shrub/bush. <span class='term'>wĕšōreš rĕṯāmîm laḥmām</span> — 'the root of the broom plant is their food' — rōṯem (broom plant, Retama raetam) is used as fuel in Ps 120:4 and 1 Kgs 19:4-5; digging its roots for food marks extreme destitution. The two plants together — saltbush leaves and broom roots — mark a diet below any tolerable subsistence level.</p>",
    "5": "<p><span class='term'>min-gēw yĕgōrāšû</span> — 'they are driven out from human society' — gēw (the midst of community, the middle); yĕgōrāšû from gāraš (to expel/drive away, the verb of divorcing and expelling — Gen 4:14 uses it for Cain's expulsion). <span class='term'>yirʾû-bô yārîʿû kĕgannāḇ</span> — 'people shout after them as after a thief' — the hue-and-cry against a thief (Exod 22:2-3 describes the thief caught in the act) applied to these wanderers; they are treated as criminals by their mere presence.</p>",
    "6": "<p><span class='term'>lišḵōn bĕnaḥălê nĕḥālîm</span> — 'to dwell in the gullies of ravines' — naḥal (wadi/ravine) + the diminutive nĕḥālîm forms 'gullies within ravines' — the most remote and inhospitable terrain. <span class='term'>ḥōrê ʿāpār wĕkêpîm</span> — 'holes of the earth and among the rock-crevices' — ḥōr = hole/burrow; kêp̄ = craggy rock surface; the imagery of people forced underground into animal burrows. The same vocabulary governs Heb 11:38's description of OT heroes who 'wandered in deserts and mountains, and in caves and holes in the ground.'</p>",
    "7": "<p><span class='term'>bên-śîḥîm yinhāqû</span> — 'among the bushes they bray' — nāhaq is the verb for a donkey braying (27:1); applied to people it is deeply dehumanizing. <span class='term'>taḥat ḥărûl yĕsuppāḵû</span> — 'beneath the nettles they are gathered together' — ḥārûl = thorn/nettle plant; sāpaḵ (to gather/pile); they huddle under thorn plants. The verse pairs donkey-braying with thorn-sheltering as the final images of sub-animal existence.</p>",
    "8": "<p><span class='term'>bĕnê-nāḇāl gam-bĕnê bĕlî-šēm</span> — 'children of the base fool, children of namelessness' — nāḇāl is the biblical word for the moral-intellectual fool who denies God (Ps 14:1 'the nāḇāl says in his heart there is no God'; Prov 17:21; 1 Sam 25:25 where Nabal's name matches his character). <span class='term'>bĕlî-šēm</span> — 'without a name/without reputation' — to be without šēm (name) in the ancient world is to be without social identity, honor, or perpetuation; the worst state short of non-existence. <span class='term'>nikkĕʾû min-hāʾāreṣ</span> — 'they were flogged/driven out of the land' — nāḵāʾ (to smite/beat); the passive describes expulsion by force.</p>",
    "9": "<p><span class='term'>wĕʿattāh nĕgînāṯām hāyîṯî</span> — 'and now I have become their song' — nĕgînāh is a musical-instrument piece or mocking song; in Lam 3:14 the same word describes the speaker becoming 'the song of all the people.' <span class='term'>wāʾĕhî lāhem lĕmillāh</span> — 'and I have become a byword to them' — millāh is word/byword/proverb; the once-honored patron becomes the content of their mockery. The full reversal of ch29's honor is now explicit: the one who commanded respect is now entertainment for social rejects.</p>",
    "10": "<p><span class='term'>tĕʿāḇûnî rāḥăqû mimmennî</span> — 'they abhor me and keep their distance' — tāʿab (to abominate/make detestable, a strong disgust-word used in Ps 5:6; 14:1 for God's rejection of evil); the same root that governs Job's self-description in 9:31. <span class='term'>ûmippānay lō-ḥāśĕkû rōq</span> — 'and they do not withhold spitting in my face' — rōq = saliva/spitting; spitting was the ultimate act of contempt (Num 12:14; Deut 25:9; Isa 50:6 where the Servant has his face spat upon). The connection between Job's suffering and the Servant of Isa 50:6 (who 'did not hide his face from insult and spitting') is one of the chapter's most significant poetic echoes.</p>",
    "11": "<p><span class='term'>kî yitrô pittaḥ wayyĕʿannēnî</span> — 'because he has loosed his cord and afflicted me' — yeter (cord/string, used for a bow-string or tent-cord); loosing it = releasing the tension that previously kept things in check. The subject is disputed: is it God who loosed Job's cord (his restraint), or has Job's affliction itself been loosed? The MKT renders this as God loosening the restraint over Job's mockers. <span class='term'>wĕriṣṣāh šillĕḥû mippānāy</span> — 'and they cast off all restraint in my presence' — šillēaḥ + riṣṣāh (the bridle or restraint); once God withdraws the protective force that commanded respect, every social inhibition against mistreating Job is removed.</p>",
    "12": "<p><span class='term'>ʿal-yāmîn pirhāḥ yāqûmû</span> — 'on my right the rabble rises up' — pirhāḥ is a rare word (only here) often understood as 'brood/mob' or 'rabble'; it may derive from pāraḥ (to sprout/spread). <span class='term'>riglay šillēḥû wayyāsōllû ʿālay</span> — 'they push aside my feet and build their roads of ruin against me' — rŏgel (foot/leg); sālaʿ (to mound/build a siege-ramp); the military metaphor of a siege is applied to the mob: they are constructing an assault route against Job.</p>",
    "13": "<p><span class='term'>nāṯĕsû nĕṯîḇāṯî</span> — 'they wreck my path' — nāṯaś (to pull down, used of demolishing walls in 2 Kgs 25:10); nĕṯîḇāh = path/course. <span class='term'>lĕhawwāṯî yôʿîlû</span> — 'they advance my downfall' — yāʿal (to profit/advance) used ironically: their 'profit' is Job's destruction; hawwāh = downfall/calamity (used in Ps 5:9; 38:12; 52:2). <span class='term'>lō ʿōzēr lāmô</span> — 'with no one to help them' — they accomplish Job's destruction without even needing outside assistance; the passivity of isolation is underscored.</p>",
    "14": "<p><span class='term'>kĕp̄ereṣ rāḥāḇ yĕḇōʾû</span> — 'they come in through a wide breach' — pereṣ (breach in a wall, used in 2 Sam 5:20 and Amos 4:3 for military breaches); the wide-breach image continues the siege metaphor. <span class='term'>taḥat šōʾāh hiṯgalgālû</span> — 'they rush in amid the ruin/catastrophe' — šōʾāh (catastrophe/devastation, used in 38:15; Prov 1:27; Zeph 1:15 for divine judgment); hitgalgal (to roll/rush in). The entire passage (vv12-14) uses warfare imagery to describe social abandonment as a military assault.</p>",
    "15": "<p><span class='term'>hāhpak ʿālay ballāhôṯ</span> — 'terrors have been turned loose against me' — ballāhôṯ (plural of ballāhāh, terrors/sudden frights) is a key Job term (9:34; 13:21; 18:11,14; 24:17); pl. indicates overwhelming multiplicity. <span class='term'>tirrōdep̄ kārûaḥ nĕḏîḇāṯî</span> — 'my dignity has been chased away like the wind' — nāḏîḇāh (dignity/princely quality, from nāḏîḇ = noble); the wind-chasing image for something ungraspably gone. <span class='term'>kĕʿāḇ ʿāḇĕrāh yĕšûʿāṯî</span> — 'my prosperity has passed away like a cloud' — yĕšûʿāh (deliverance/prosperity) normally used for divine salvation (cf. Ps 3:2; Isa 12:2 'God is my yĕšûʿāh'); its application to social/material prosperity shows how completely Job's world has been the arena of divine blessing.</p>",
    "16": "<p><span class='term'>wĕʿattāh ʿālay tiššāpēḵ nap̄šî</span> — 'and now my soul is poured out upon me' — šāpak (to pour out, used of blood: Gen 9:6; and of water: 2 Sam 14:14); nepeš (soul/life) poured out like a liquid. This exact construction — nep̄eš + šāpak + ʿāl — appears in Ps 22:14 ('I am poured out like water... my heart has melted like wax'); the Psalm of dereliction uses the same self-dissolution language Job uses here. <span class='term'>yōʾḥăzûnî yĕmê ʿānî</span> — 'days of affliction have seized me' — ʿŏnî (affliction/poverty from ʿānāh, to be afflicted); the days of affliction as a grasping agent, seizing Job in their grip.</p>",
    "17": "<p><span class='term'>laylāh ʿaṣmōṯay niqar mēʿālay</span> — 'at night my bones are racked/bored through' — nāqar (to bore/pierce, used in 2 Kgs 25:7 for boring out eyes); the night pain gnaws at Job's skeletal structure. <span class='term'>wĕʿōrĕqay lō yiškāḇû</span> — 'and the gnawing pain does not rest' — ʿōreq (from nāqar? or from ʿāraḵ = to gnaw?) — the pain as a living thing that does not sleep even when Job tries to; the sleeplessness of chronic pain given poetic form.</p>",
    "18": "<p><span class='term'>bĕrāḇ-kōaḥ yitḥappēś lĕḇûšî</span> — 'with great force my garment is seized' — ḥāp̄aś (to disguise/search through; in the hitpa'el to grip/hold tightly). The garment-seizing by illness: disease literally grabs and distorts Job's clothing, twisting it around him. <span class='term'>kĕp̄î kuttontî yaʾăzrēnî</span> — 'it binds me like the collar of my tunic' — ketonnet (the long garment/tunic; the same word as Joseph's coat in Gen 37:3); the collar (pî = mouth/opening) becomes a strangling grip. Disease as a garment-seizing assailant is a striking pathological image.</p>",
    "19": "<p><span class='term'>hōrānî laḥōmer</span> — 'he has thrown me into the mud' — yārāh in the hip'il = to throw; ḥōmer = clay/mud; to be thrown into mud is to be reduced to raw material. <span class='term'>wāʾetmassēl kĕʿāpār wāʾēp̄er</span> — 'and I have become like dust and ashes' — māšal (to be like, to resemble); ʿāpār wāʾēp̄er — the dust-and-ashes pair is the standard OT expression for the absolute lowness of human creaturely existence (Gen 18:27; Job 42:6); to become the metaphor itself is the deepest descent.</p>",
    "20": "<p><span class='term'>ʾeśāʿaq ʾēlêḵā wĕlō taʿănēnî</span> — 'I cry out to you and you do not answer me' — šāʿaq (to cry out in distress, the verb of desperation); the divine non-answer as active theological abandonment. This is the direct parallel to Ps 22:2 ('I cry by day and you do not answer'). <span class='term'>ʿāmadtî wattitbōnēn bî</span> — 'I stand and you only stare at me' — bîn (to understand/perceive) in the hitpo'el = to stare with incomprehension; God is portrayed as observing without responding. The combination of the divine silence motif and the divine-gaze motif frames Job's abandonment experience in terms almost identical to the messianic Psalm of dereliction.</p>",
    "21": "<p><span class='term'>hēhāp̄aḵ lĕʿākzār lî</span> — 'you have become cruel to me' — ʿakzār (cruel/savage, used in Prov 5:9; Isa 13:9 for God's judgment-day cruelty against enemies); Job is experiencing the treatment reserved for enemies applied to himself. <span class='term'>bĕʿōṣem yāḏĕḵā tiśṭĕmēnî</span> — 'with the power of your hand you persecute me' — śāṭam (to oppose/be hostile to; cf. Gen 27:41, Esau's hostility; and Satan's root in this stem in 1:6 interpretations); the divine hand as adversarial rather than protective.</p>",
    "22": "<p><span class='term'>tiśśāʾēnî ʾel-rûaḥ tarkîḇēnî</span> — 'you lift me up to the wind; you cause me to ride it' — rāḵaḇ (to ride, used in Deut 33:26 for God who rides the heavens); Job being made to ride the wind = total disorientation and helplessness. <span class='term'>wĕtĕmōgĕgēnî tûšiyyāh</span> — 'and you dissolve my substance/effective power' — mûg (to melt/dissolve); tûšiyyāh (the distinctive Job word for effective wisdom/substance, also in 6:13; 11:6; 12:16; 26:3; Prov 8:14); Job's capacity for purposeful action is melted away by God's storm-riding.</p>",
    "23": "<p><span class='term'>kî-yāḏaʿtî māwet tĕšîḇēnî</span> — 'for I know you will bring me to death' — the only certainty left is that God will direct Job toward death. <span class='term'>wĕḇêṯ môʿēḏ lĕḵol-ḥāy</span> — 'to the house appointed for all living' — bêṯ môʿēḏ is a remarkable compound: bêṯ (house) + môʿēḏ (the term for the divinely appointed Tabernacle/Temple meeting-place, as in ʾōhel môʿēḏ = tent of meeting). Death is called a 'house of appointment/meeting'; the irony that the Tabernacle-meeting language — the locus of divine-human encounter — should be applied to death is bitter and theologically charged.</p>",
    "24": "<p><span class='term'>ʾaḵ lō-bĕʿî yišlaḥ yāḏ</span> — 'yet does not one in a ruin reach out his hand?' — the verse is difficult; the sense seems to be: even in a heap of ruins, people reach out and cry for help. Job is asserting the universal practice of crying for help in disaster as the ground for his own cries. The appeal to common human practice challenges any theology that would silence the sufferer's cry.</p>",
    "25": "<p><span class='term'>ʾim-lō bāḵîṯî lĕqĕšēh-yôm</span> — 'did I not weep for those in trouble?' — qāšâ yôm = hard/difficult day, the day of hardship; Job's past compassion for others in distress. <span class='term'>ʾāgĕlāh nap̄šî lāʾeḇyôn</span> — 'was not my soul grieved for the poor?' — ʾāgal (to have grief/sorrow, related to Arabic root for deep interior distress); nepeš + ʾāgal for the poor echoes the socially engaged righteousness of ch29. Having wept for others' distress, Job expects (and receives instead) divine indifference to his own.</p>",
    "26": "<p><span class='term'>kî ṭôḇ qiwwîṯî wayyāḇōʾ rāʿ</span> — 'when I looked for good, evil came' — the bitterest reversal formula: qiwwîṯî (I hoped/waited, the verb of tiqwāh, hope) for ṭôḇ (good) but rāʿ (evil) came. The language of hope-and-disappointment is applied not to a single event but to the whole shape of Job's life after his integrity. <span class='term'>wăʾăyahel lāʾôr wayyāḇōʾ ʾōp̄el</span> — 'and when I waited for light, thick darkness came' — ʾōp̄el (thick darkness, the same darkness of the inward parts of Job 3:6 and Prov 7:9); the antithesis of hoped-for light arriving as its opposite.</p>",
    "27": "<p><span class='term'>mēʿay ḥārû wĕlō-ḏāmû</span> — 'my inner parts churn and do not rest' — ḥārāh (to burn/ferment; applied to the gut here as visceral turmoil); the meʿāyim (intestines/inner parts) as the seat of emotion mirrors Jer 4:19 ('my bowels, my bowels! I am pained at my very heart') and Lam 1:20. <span class='term'>qiddĕmûnî yĕmê ʿānî</span> — 'days of affliction have overtaken/confronted me' — qāḏam (to come before/confront, used in Ps 18:18 of enemies who came against); the days of affliction as active assailants meeting Job head-on.</p>",
    "28": "<p><span class='term'>qōḏēr hillaḵtî bĕlō ḥammāh</span> — 'I go about in mourning without the sun' — qāḏar (to be dark/gloomy; used in 1 Kgs 18:45 of the sky blackening; applied to mourning dress in Ps 35:14; 42:9); ḥammāh = the sun (a poetic word, the warm/heat-giver). Mourning without the sun's comfort. <span class='term'>ʾāqûm baqāhāl ʾăšawwēaʿ</span> — 'I stand in the assembly and cry out' — qāhāl (the formal assembly of the community); šāwaʿ (to cry for help, the most urgent help-cry). Job's public, communal, unanswered cry for help.</p>",
    "29": "<p><span class='term'>ʾāḥ hāyîṯî lĕṯannîm</span> — 'I have become a brother to jackals' — ʾāḥ (brother) with tannîm (jackals, or possibly sea-monsters; in Isa 13:21-22 and 34:13-15, jackals and ostriches inhabit desolate ruins, emblems of Edom's judgment). <span class='term'>wĕrēʿa lĕḇnôṯ yaʿănāh</span> — 'and a companion to ostriches' — rēaʿ (friend/companion); yaʿănāh (ostrich or possibly the screech-owl; its mournful cry makes it a wilderness-mourning symbol in Mic 1:8; Lam 4:3). The social companionship of the desolate creatures replaces human fellowship.</p>",
    "30": "<p><span class='term'>ʿôrî šāḥar mēʿālay</span> — 'my skin has turned black on me' — šāḥar (to be dark; the same word as 'dawn' but here applied to skin darkening through disease or sun-exposure); the irony of using the dawn-word for skin-blackening. <span class='term'>wĕʿaṣmî-ḥārāh miqqaḏḏāḥaṯ</span> — 'and my bones burn with fever' — ḥārāh (to burn/be hot); qaddaḥat (fever/inflammation, also in Lev 26:16; Deut 28:22 as a covenant-curse); Job's body manifesting the covenant-curse vocabulary.</p>",
    "31": "<p><span class='term'>wayhî lĕʾēḇel kinnōrî</span> — 'my lyre has become mourning' — kinnôr (the stringed instrument, David's instrument and the instrument of praise in Ps 33:2; 43:4; 150:3); turned to ʾēḇel (mourning, the term for the formal mourning period; Gen 27:41; Amos 5:16). <span class='term'>wĕʿûgāḇî lĕqôl bōḵîm</span> — 'and my flute to the sound of weeping' — ʿûgāḇ (a wind instrument, probably the flute; Gen 4:21 lists it as Jubal's instrument alongside the kinnor); bōḵîm (weeping ones). The chapter closes with the reversal of musical praise into mourning lamentation — the full range of cultural expression now in the service of grief.</p>"
  },
  "31": {
    "1": "<p><span class='term'>bĕrît kāraṯî lĕʿênāy</span> — 'I cut a covenant with my eyes' — kārat bĕrît is the standard idiom for formal covenant-making (Gen 15:18; 21:27; Exod 24:8); applied to the eyes it elevates visual discipline to the status of a binding legal agreement. The eyes as parties to a covenant is uniquely rigorous: not 'I tried not to look' but 'I am covenantally obligated not to look.' <span class='term'>ûmāh ʾetbônān ʿal-bĕṯûlāh</span> — 'how then could I gaze at a young woman?' — bĕṯûlāh (a young woman of marriageable age, often translated 'virgin'); bîn in the hitpo'el = to look at intently/contemplate. The eye-covenant becomes the foundation for Jesus's intensification of the prohibition in Matt 5:28 ('everyone who looks at a woman to lust after her has already committed adultery with her').</p>",
    "2": "<p><span class='term'>wĕmāh ḥēleq ʾĕlôah mimāʿal</span> — 'what is God's portion from above?' — ḥēleq (allotment/portion, the term used for Levitical inheritance and land distribution); God's 'portion' here means what God assigns as consequence. <span class='term'>wĕnaḥălat Šaddai mimmĕrōmîm</span> — 'and the inheritance of Shaddai from the heights?' — naḥălāh (inheritance/heritage, the covenantal land-promise word); the verse grounds Job's ethical behavior not in personal virtue alone but in the framework of divine reward-structure (even as he maintains his integrity despite that structure apparently having failed him).</p>",
    "3": "<p><span class='term'>hălō-ʾêḏ lĕʿawwāl</span> — 'is not ruin for the wrongdoer?' — ʾêḏ (calamity/disaster, the destruction that arrives); ʿawwāl (one who is crooked/unjust; from ʿāwal = to be bent, the root of ʿawlāh = injustice). <span class='term'>wĕnēḵar lĕp̄ōʿălê ʾāwen</span> — 'and disaster for those who work iniquity?' — nēḵar (foreign/strange, used as a noun for 'estrangement/alienness'); pōʿălê ʾāwen (workers of trouble/iniquity, a fixed phrase from the Psalms: 5:5; 6:8; 14:4). Job is affirming the retributive framework as a general principle — but his experience contradicts its application to his specific case.</p>",
    "4": "<p><span class='term'>hălō-hûʾ yirʾeh ḏĕrāḵay</span> — 'does he not see my ways?' — the rhetorical certainty that God observes: this is simultaneously the ground of Job's confidence in his innocence (God sees that I am not guilty) and his perplexity (God sees but does not respond appropriately). <span class='term'>wĕḵol-ṣĕʿādāy yispôr</span> — 'and counts all my steps?' — sāpar (to count/number) of the divine accounting of human movement; the same forensic oversight Job complained about in 14:16 is here offered as a reason for confidence in his vindication — since God's scrutiny would reveal nothing amiss.</p>",
    "5": "<p><span class='term'>ʾim-hālaktî ʿim-šāwʾ</span> — 'if I have walked with falsehood/emptiness' — šāwʾ (emptiness/vanity/falsehood; used in the third commandment 'do not take the name of the LORD in vain/šāwʾ'; and in Job 7:3; 15:31; 35:13); applying it to walking = living by deception. <span class='term'>wattĕḥaš ʿal-mirmāh raglî</span> — 'and my foot has rushed toward deceit' — mirmāh (deceit/treachery; the same word used of Jacob's deception in Gen 27:35 — 'your brother came with deceit/mirmāh'); the ethical autobiography continues with a negative conditional catalogue.</p>",
    "6": "<p><span class='term'>yišqĕlēnî bĕmōʾznê ṣeḏeq</span> — 'let me be weighed in honest/just scales' — mōʾznê ṣeḏeq (scales of righteousness/justice) is the idiom of Lev 19:36 and Prov 16:11 ('honest scales and balances are the LORD's'); Job invites the divine weighing that Prov 21:2 warns about. <span class='term'>wĕyēḏaʿ ʾĕlôah tummāṯî</span> — 'and let God know my integrity' — tummāh (integrity/wholeness, from tāmam = to be complete; the same root as Job's description in 1:1 and 1:8); the invitation to divine knowledge of his integrity is both a legal demand and an act of radical transparency.</p>",
    "7": "<p><span class='term'>ʾim tāṭeh ʾaššurî min-haddāreḵ</span> — 'if my step has turned from the path' — ʾaššûr (step/walk, poetic synonym for going; cf. Ps 17:5 'my steps have held to your paths'); min-haddāreḵ (from the right path). <span class='term'>wĕʾaḥar ʿênay hālaḵ libbî</span> — 'and my heart has followed my eyes' — the inversion of proper order: the heart should govern the eyes (not vice versa); when the eyes lead the heart, desire precedes judgment. <span class='term'>ûḇĕḵappay dāḇaq mûm</span> — 'and any stain has clung to my hands' — mûm (blemish/defect, the word for a physical blemish disqualifying a priest in Lev 21:17-23; applied here morally).</p>",
    "8": "<p><span class='term'>ʾezrāʿāh wĕʾaḥēr yōʾḵēl</span> — 'let me sow and another eat' — the curse-formula for violated covenantal labor (Deut 28:30,33,51: the covenant curses include others consuming what you plant); Job invites these curses upon himself if guilty. <span class='term'>wĕṣeʾĕṣāʾay yĕšōrāšû</span> — 'and let my offspring be uprooted' — ṣeʾĕṣāʾ (offspring/descendants, from the root of 'going out'); šāraš in the po'al = to be uprooted by the roots; dynastic obliteration as the sworn consequence.</p>",
    "9": "<p><span class='term'>ʾim-nip̄tāh libbî ʿal-ʾiššāh</span> — 'if my heart has been enticed by a woman' — pāṯāh (to entice/seduce; the same verb used in Exod 22:16 for seducing a virgin, and in Prov 1:10 for sinners enticing the young); the heart as the primary site of sexual temptation, not just the eye (v1). <span class='term'>wĕʾarāḇtî ʿal-pétaḥ rēʿî</span> — 'or if I have lurked at my neighbor's door' — ʾāraḇ (to lie in wait/ambush, the verb of setting a trap; used in Prov 1:11,18; 7:12 for the wayward woman); lurking at the neighbor's door = the precise act prohibited in the commandment against coveting the neighbor's wife.</p>",
    "10": "<p><span class='term'>tiṭḥan lĕʾaḥēr ʾišṯî</span> — 'let my wife grind for another' — ṭāḥan (to grind grain, the work of a slave-concubine in Exod 11:5; Num 11:8; Isa 47:2); to grind for another = to be sexually enslaved to another. <span class='term'>wĕʿālêhā yiḵrĕʿûn ʾăḥērîm</span> — 'and let others bow over her' — kāraʿ (to bow down/kneel; used in sexual contexts in Gen 49:9; Judg 5:27); the sworn curse-consequence of adultery is his own wife's sexual degradation. The brutal reciprocity of the oath formula reflects how seriously the social fabric of family and neighbor honor was taken.</p>",
    "11": "<p><span class='term'>kî-hîʾ zimmāh</span> — 'for that would be a deliberate outrage' — zimmāh is the strongest OT word for sexual wickedness: deliberate, calculated, outrageous depravity (Lev 18:17; 19:29; 20:14; Ezek 16:27; 22:9; Prov 10:23); distinguished from mere passion by its premeditated character. <span class='term'>wĕhîʾ ʿāwōn pĕlîlîm</span> — 'and an iniquity deserving judges' — pĕlîlîm (judges/referees; from pālal = to judge/mediate); the phrase 'iniquity of/for judges' = a crime serious enough to require judicial adjudication, not merely personal repentance.</p>",
    "12": "<p><span class='term'>kî ʾēš hîʾ ʾaḏ-ʾăḇaddôn tōʾḵēl</span> — 'for it is a fire that burns all the way to Abaddon' — ʾăḇaddôn (destruction/the underworld realm, from ʾāḇaḏ = to perish; used in Job 26:6; 28:22; Ps 88:11; Prov 15:11; Rev 9:11 where it names the angel of the bottomless pit as Abaddon). The fire of sexual betrayal burns to the depths of the realm of destruction — its consequences are eschatologically profound. <span class='term'>wĕḇĕḵol-tĕḇûʾāṯî tĕšarrēš</span> — 'and would consume all my harvest' — šāraš in the pi'el = to uproot entirely; tĕḇûʾāh = produce/income/harvest. Total economic destruction as the consequence of sexual sin.</p>",
    "13": "<p><span class='term'>ʾim-ʾemʾas mišpaṭ ʿaḇdî wĕʾāmāṯî</span> — 'if I have dismissed the legal case of my servant or maidservant' — mišpāṭ (legal right/case/judgment); mĕʾēn (to refuse); ʿeḇed and ʾāmāh (male servant and female servant) — both gendered servants have legal standing in this oath. The willingness to acknowledge servant legal rights is remarkable; most ancient law systems gave the master almost total discretion over servants. <span class='term'>bĕriḇām ʿimmāḏî</span> — 'when they had a legal dispute with me' — rîḇ (dispute/lawsuit); ʿim (with/against); the servant as legal adversary of the master in a binding adjudication.</p>",
    "14": "<p><span class='term'>wĕmāh ʾeʿĕśeh kî-yāqûm ʾēl</span> — 'what could I do when God rises up?' — qûm (to rise; used in legal contexts for the rising of a judge or accuser to pronounce judgment; cf. Isa 2:19,21 where God 'rises'); Job appeals to divine legal oversight as his ultimate accountability. <span class='term'>wĕkî yip̄qōḏ māh ʾăšîḇennû</span> — 'when he holds inquiry, what shall I answer him?' — pāqaḏ (to visit/examine/hold to account, the verb of divine visitation both in judgment and blessing; Exod 20:5; 32:34); the servant-equity clause flows from the recognition that God himself will audit Job's conduct toward those beneath him.</p>",
    "15": "<p><span class='term'>hălō-ḇabbeṭen ʿōśēnî ʿāśāhû</span> — 'did not the one who made me in the womb make him also?' — the argument from common creatureliness: both master and servant were fashioned by the same divine Maker in the womb (bāṭen = womb/belly). <span class='term'>wayyĕḵûnennû bāreḥem ʾeḥāḏ</span> — 'and did not one God form us both in the womb?' — ʾeḥāḏ (one); rāḥem (womb); the theological anthropology here — one Creator, one womb, therefore one humanity that transcends status — anticipates Paul's 'there is neither slave nor free' (Gal 3:28) and James's appeal to a common creation as the ground for not discriminating between rich and poor (James 2:1-7).</p>",
    "16": "<p><span class='term'>ʾim-ʾemnaʿ mēḥēp̄eṣ dallîm</span> — 'if I have withheld what the poor needed' — dallîm (the poor/weak, from ḏal = to hang thin/be weak; Exod 30:15; Lev 14:21); ḥēp̄eṣ (desire/what is wanted); withholding what the poor desired = failing to meet actual need. <span class='term'>wĕʿênê ʾalmānāh ʾăkalleh</span> — 'or caused the widow's eyes to fail from waiting' — kāllāh (to fail/be consumed; used in Ps 84:2 'my soul faints/kāllāh with longing'); the widow's eyes failing from sustained waiting — she has waited so long for help that even hope of it has been exhausted.</p>",
    "17": "<p><span class='term'>wĕʾōḵal pittî lĕḇaḏḏî</span> — 'or if I ate my food alone' — pittāh (piece of bread/food; the most basic meal unit); lĕḇaḏḏ (alone/by oneself); the ethics of the shared table: in the ancient Near East, eating without sharing was a serious social offense. <span class='term'>wĕlō-ʾāḵal yāṯôm mimmenāh</span> — 'and the fatherless ate nothing from it' — yātôm (the fatherless child, whose special legal protection runs from Exod 22:22 through the Psalms and prophets); the shared meal as the concrete measure of social righteousness.</p>",
    "18": "<p><span class='term'>kî minnĕʿûrāy gĕḏēlānî kĕʾāḇ</span> — 'for from my youth he grew up with me as with a father' — gāḏal (to grow up/be raised); the surprising identification of the fatherless as one who 'grew up with' Job as a father-figure. <span class='term'>ûminneṭen ʾimmî ʾanḥennāh</span> — 'and from birth I cared for the widow' — min-beṭen ʾem (from the womb of one's mother, a hyperbole for 'from earliest time'); nāḥāh (to guide/lead in the sense of pastoral care). Job's fathering of the fatherless and guiding of widows is presented as a lifelong character-formation, not occasional charity.</p>",
    "19": "<p><span class='term'>ʾim-ʾerʾeh ʾôḇēḏ mibbelî lāḇûš</span> — 'if I have seen anyone perishing for lack of clothing' — ʾāḇaḏ (to perish/be lost; here with min-belî = 'without'); lāḇûš (clothing, the basic covering); the naked poor encountered (rāʾāh = seen) rather than helped. <span class='term'>wĕʾên kĕsûṯ lāʾeḇyôn</span> — 'or any poor person without covering' — ʾeḇyôn (the needy/destitute, a stronger economic term than dallîm); kĕsûṯ (covering/garment); the visual encounter with naked poverty as the trigger for the ethical obligation.</p>",
    "20": "<p><span class='term'>ʾim-lō bĕrăḵûnî ḥălāṣāyw</span> — 'if he has not blessed me from his very loins' — ḥălāṣayim (the loins/hips, the body-part of warmth and strength; in Gen 35:11 'from your loins kings will come'); the blessing from the body = deep visceral gratitude, not polite thanks. <span class='term'>ûmigēz kĕḇāśāy yiṯḥammām</span> — 'and the wool of my sheep has not kept him warm' — gēz (shearing/fleece); the warm wool from Job's own flocks goes to warm the poor who bless him with embodied gratitude; practical material generosity confirmed by the recipient's bodily warmth.</p>",
    "21": "<p><span class='term'>ʾim-hănîp̄ôṯî ʿal-yāṯôm yāḏî</span> — 'if I have raised my hand against the fatherless' — hānap̄ (to wave/brandish); the hand raised against the orphan as a gesture of threat or violence. <span class='term'>kî ʾerʾeh bĕšaʿar ʿezrāṯî</span> — 'when I see my support at the city gate' — šaʿar (city gate, the locus of judicial proceedings and public power in the ancient city; Gen 19:1; Ruth 4:1-2; Amos 5:12); ʿezrāh (support/help); to have allies at the gate = to have judicial power; Job swears he did not exploit that power against the most vulnerable.</p>",
    "22": "<p><span class='term'>kĕṯēp̄î missĕḵmāh tippôl</span> — 'let my arm fall from its shoulder' — kāṯēp̄ (shoulder-blade/shoulder-joint); min-šĕḵem (from the shoulder); the imprecatory self-curse for using power against the fatherless: may the arm that could raise itself against the helpless be torn from its socket. <span class='term'>wĕzĕrōʿî miqqāneh tiššāḇēr</span> — 'and my arm be broken from the elbow' — zĕrôaʿ (arm/forearm, the seat of strength; used in Ezek 4:7; Deut 33:27 for the divine arm); tiššāḇēr = 'be broken/shattered'; the double anatomical curse (shoulder joint + forearm) ensures the arm of injustice is permanently disabled.</p>",
    "23": "<p><span class='term'>kî p̄aḥaḏ ʾēlî ʾêḏ ʾēl</span> — 'for the destruction from God is a terror to me' — paḥaḏ (dread/terror; used in 3:25 for what Job feared coming upon him); ʾêḏ ʾēl = 'the calamity of God' (the divine disaster, also in Isa 10:3; Prov 1:26); Job's ethical behavior is motivated not only by compassion but by healthy fear of divine accountability. <span class='term'>ûmiśśĕʾēṯô lō ʾûḵāl</span> — 'before his majesty I cannot hold my ground' — śĕʾēṯô (his rising/majesty; the same word as 13:11); the towering divine majesty silences any thought of exploitation.</p>",
    "24": "<p><span class='term'>ʾim-śamtî zāhāḇ kislî</span> — 'if I have made gold my trust/hope' — śwm + kislî (to set/place + my hope/security; kesel = the fat of the loins as seat of confidence, or simply confidence itself; cf. Ps 78:7 'to set their hope in God'); gold as alternative ground of security. <span class='term'>wĕlakkettêm ʾāmartî mibṭaḥî</span> — 'or called refined gold my security' — kéttem (fine gold, a poetic term appearing in 28:19; Ps 45:9; Prov 25:12; Song 5:11); miḇṭāḥ (trust/security; from bāṭaḥ = to trust; Ps 40:4; Jer 17:5-7 contrasts trust in humans with trust in God). The prohibition on financial security as primary trust is grounded here in a negative oath; Ps 52:7 and 1 Tim 6:17 make the same prohibition positive.</p>",
    "25": "<p><span class='term'>ʾim-ʾeśmaḥ kî-rāḇ ḥêlî</span> — 'if I rejoiced that my wealth was great' — śāmaḥ (to rejoice/delight in; the delight-verb for Ps 97:12 'rejoice in the LORD'); rāḇ ḥayil = 'great wealth/army-force' (ḥayil = military force/wealth); joy in wealth-magnitude rather than in God. <span class='term'>wĕkî-ḵaḇbîr māṣĕʾāh yāḏî</span> — 'and that my hand had gained much' — kāḇîr (much/great; rare poetic word); the pride of self-made wealth as the spiritual danger. Job renounces both the accumulation-pride and the abundance-joy.</p>",
    "26": "<p><span class='term'>ʾim-ʾerʾeh ʾôr kî yāhēl</span> — 'if I gazed at the light as it shines brilliantly' — ʾôr (light, the sun) yāhēl (shines brilliantly; from hālal in the sense of shining, the same root as hallelujah); <span class='term'>wĕyārēaḥ yāqār hōlēḵ</span> — 'and the moon as it moves in splendor' — yāqār (precious/glorious); astral worship through contemplative gazing. The prohibition on sun and moon worship runs from Deut 4:19; 17:3 through Jer 8:2; Ezek 8:16; the widespread nature of this temptation is reflected in how carefully Job includes it in his oath.</p>",
    "27": "<p><span class='term'>wayyippaṯ basseṯer libbî</span> — 'and my heart was secretly seduced' — pāṯāh (to be enticed/seduced, the same verb as v9's heart-enticed-by-a-woman); the heart's private corruption — the inner liturgy of astral veneration that precedes any public act. <span class='term'>wattišśaq-yāḏ lĕp̄î</span> — 'and my hand was thrown a kiss toward them' — the kiss blown toward the celestial body (hand to mouth to the sky) was the classic gesture of astral worship known from Mesopotamian and Egyptian practice; 1 Kgs 19:18 uses the same idiom ('all who have not bowed to Baal and every mouth that has not kissed him').</p>",
    "28": "<p><span class='term'>gam-hûʾ ʿāwōn pĕlîlî</span> — 'this too would be an iniquity deserving judgment' — the same legal formula as v11 (zimmāh + ʿāwōn pĕlîlî); sexual betrayal and idolatry are given identical legal weight. <span class='term'>kî-ḵiḥaštî lāʾēl mimmāʿal</span> — 'for I would have denied the God above' — kāḥaš (to deceive/deny by minimizing; used in Josh 7:11 for the denial of wrongdoing; Lev 19:11 'do not deny/deceive'); to worship the sun or moon is to deny ʾēl mimmāʿal (the God who is above/over) — the astral bodies are subordinate to the Creator, and worshiping them denies the hierarchy of being.</p>",
    "29": "<p><span class='term'>ʾim-ʾeśmaḥ bĕp̄îḏ śōnĕʾî</span> — 'if I rejoiced at the ruin of one who hated me' — p̄îḏ (destruction/downfall; only here and 12:5; 21:20; 30:24; 31:3 — a rare Joban term for disaster); śōnēʾ (one who hates/is hostile); joy at an enemy's ruin. <span class='term'>wĕhitʿôrartî kî-māṣāʾhû rāʿ</span> — 'or exulted when disaster found him' — hitʿôrēr (to rouse/excite oneself in po'lel; to be stirred up with excitement); this oath clause anticipates Prov 24:17 ('do not rejoice when your enemy falls') and Christ's command to love enemies (Matt 5:44).</p>",
    "30": "<p><span class='term'>wĕlō-nāṯattî laḥăṭōʾ ḥiḵḵî</span> — 'I did not let my mouth sin' — ḥēḵ (palate/mouth, the tasting organ of 12:11); nāṯan + laḥăṭōʾ = to give/allow to sin; the mouth as the instrument of verbal sin in asking God for the enemy's death. <span class='term'>lišʾōl bĕʾālāh nap̄šô</span> — 'by asking for his life with a curse' — ʾālāh (oath/curse; the solemn curse-word; Gen 24:41; Num 5:21); the prohibition on cursing the enemy to death extends the ethic of v29 from internal rejoicing to verbal action.</p>",
    "31": "<p><span class='term'>ʾim-lō ʾāmĕrû mĕṯê ʾāholî</span> — 'if the men of my household have not said' — mĕṯê ʾōhel (men of the tent/household); the household testimony as evidence: what Job's own servants and family members say about his hospitality. <span class='term'>mî-yittēn mibbĕśārô lō niśbāʿ</span> — 'who has not been filled from his food?' — the rhetorical who-has-not?: everyone in the household has been fed to fullness (śāḇaʿ = to be satisfied/full) from Job's table.</p>",
    "32": "<p><span class='term'>ballayil lō-yālîn gēr</span> — 'no stranger had to lodge in the street at night' — gēr (a stranger/sojourner, the protected alien resident whose care is commanded throughout the Mosaic law: Exod 22:21; 23:9; Lev 19:33-34; Deut 10:19); lûn (to spend the night, to lodge); the gate opened to the stranger at night is the hospitality ethic at its most demanding. <span class='term'>ḏĕlatay lāʾōrēaḥ ʾep̄tāḥ</span> — 'I opened my door to the traveller' — ʾōrēaḥ (the wayfarer/traveller; cf. Jer 14:8 where God is called 'like a stranger who turns aside to lodge'); the opened door to the traveler connects to the NT's 'do not neglect to show hospitality to strangers, for thereby some have entertained angels' (Heb 13:2).</p>",
    "33": "<p><span class='term'>ʾim-kissîṯî kĕʾāḏām pĕšāʿāy</span> — 'if I have hidden my transgressions like Adam' — kāsāh (to hide/cover; the same verb as God's covering of nakedness in Gen 3:21); pešaʿ (transgression/rebellion); the explicit comparison to Adam's hiding his sin (Gen 3:8-12) is the only unambiguous reference in OT poetry to Adam's paradigmatic sin-concealment. This makes Job 31:33 the OT antecedent to Paul's Adam typology in Rom 5:12-14 and his treatment of covering and exposing transgression in 2 Cor 4:2. <span class='term'>lĕṭamôn bĕḥûḇî ʿăwōnî</span> — 'by concealing my iniquity in my heart' — ṭāman (to hide/bury; the verb of storing treasure or setting an ambush; Prov 2:1 stores wisdom; here iniquity is 'buried' in the chest/bosom).</p>",
    "34": "<p><span class='term'>kî ʾeʿĕrōṣ hāmôn rabbāh</span> — 'because I feared the great crowd' — ʿāraṣ (to dread/be overwhelmed by; the root of marʿîṣ = terrifying; used for the numbing dread of the powerful); hāmôn rabbāh = the great crowd/multitude. <span class='term'>ûbûz mišpāḥôṯ yĕḥiṯtannî</span> — 'and the contempt of families/clans terrified me' — bûz (contempt/scorn; Prov 12:8; Ps 22:6 where the speaker is 'a worm and not a man... an object of scorn and contempt'); mišpāḥāh (clan/family group); the social pressure of communal shame is identified as the mechanism that keeps sin hidden 'like Adam': fear of public exposure rather than moral shame.</p>",
    "35": "<p><span class='term'>mî yittĕn-lî šōmēaʿ lî</span> — 'O that someone would hear me!' — the repeated mî-yittēn optative ('O that!') of Job's greatest wish: a hearing. <span class='term'>hēn-tāwî Šaddai yaʿănēnî</span> — 'here is my signature — let Shaddai answer me!' — tāw is the last letter of the Hebrew alphabet (the equivalent of omega), written as an X-mark in ancient script; to place one's tāw = to sign one's legal document. Job formally signs and presents his petition to the divine court. <span class='term'>wĕsēp̄er kāṯaḇ ʾîš rîḇî</span> — 'O that my accuser had written out his charges!' — Job's longing for a written indictment so he could actually read and respond to the charges against him; the legal right to know one's accusation. This verse stands at the center of the book's legal metaphor: Job filing his signed petition against God's silence.</p>",
    "36": "<p><span class='term'>ʾim-lō ʿal-šikmî ʾeśśāʾennû</span> — 'surely I would carry it on my shoulder' — šeḵem (shoulder, the body-part of burden-bearing; Isa 9:6 'the government shall be upon his shoulder'); Job would carry the divine indictment on his shoulder = bear it openly, proudly, as a sign of his willingness to be publicly examined. <span class='term'>ʾeʿendehu kĕʿăṭārôṯ lî</span> — 'and wear it as a crown on my head' — ʿăṭārāh (crown/garland; a mark of honor in Prov 12:4; 17:6; Isa 62:3); the indictment worn as a crown is the paradox of the wrongly-accused righteous person: what was meant to shame becomes the mark of honor.</p>",
    "37": "<p><span class='term'>mispār ṣĕʿāḏay ʾaggîḏennû</span> — 'I would give him an account of all my steps' — mispār ṣĕʿāḏay (the number of my steps; the same forensic counting of 31:4 and 14:16); Job would render a complete account of every action. <span class='term'>kĕnāgîḏ ʾeqrĕḇennû</span> — 'I would approach him like a prince' — nāgîḏ (a leader/prince, one who goes in front; used of commanders: 1 Sam 9:16; 1 Chr 9:11); Job would not approach God as a cringing defendant but as a peer — standing upright, making a dignified legal presentation. The prince-analogy is the ethical climax of Job's self-defense.</p>",
    "38": "<p><span class='term'>ʾim-ʿālay ʾadmāṯî tizʿāq</span> — 'if my land has cried out against me' — zāʿaq (to cry out; the same verb as the cry of Abel's blood in Gen 4:10 which 'cried out from the ground'); the land as a moral witness against its owner. <span class='term'>wĕyaḥad tĕlāmêhā yiḇkāyûn</span> — 'and its furrows have wept together' — telem (a furrow; the plough-line in Ps 65:10 that God's rain fills); weeping furrows personify agricultural land making a legal complaint. The oath extends from social ethics (servants, widows, orphans) to ecological ethics (land stewardship).</p>",
    "39": "<p><span class='term'>ʾim-ʾet-kōḥāh ʾāḵaltî ḇlî-ḵesep̄</span> — 'if I have eaten its produce without payment' — ḵōaḥ (power/produce; the productive force of the land); ḵesep̄ (silver/payment); consuming agricultural produce without paying its owners = land theft. <span class='term'>wĕnep̄eš bĕʿālêhā hippāḥtî</span> — 'or stripped the life/breath from its owners' — nāpah (to breathe/blow; pi'el hiṗpîaḥ = to blow out, to extinguish); nepeš bĕʿālāyw = the life of its owners; to consume the land's produce without payment is to extinguish the life-support of the legitimate owners. The ecological ethics connects directly to social ethics: land exploitation kills people.</p>",
    "40": "<p><span class='term'>taḥat ḥiṭṭāh yēṣēʾ ḥôaḥ wĕtaḥat-śĕʿōrāh bōʾšāh</span> — 'let thistles grow instead of wheat and weeds instead of barley' — ḥôaḥ (thorn/thistle; the curse-vegetation of Gen 3:18 where 'thorns and thistles' mark the fall-curse on the ground); bōʾšāh (a noxious/stinking plant, perhaps the darnel); the reversal of cultivation-to-thorn-growth is the Gen 3 curse applied as a legal penalty. <span class='term'>tammû diḇrê ʾîyôḇ</span> — 'the words of Job are ended' — tāmam (to be complete/finished; the same root as Job's own tōm = integrity); the colophon formally closes Job's speeches. His last word before the divine answer is his signature of integrity.</p>"
  },
  "32": {
    "1": "<p><span class='term'>wayyišbĕtû šĕlōšeṯ hāʾănāšîm hāʾēlleh mēʿănôṯ ʾet-ʾîyôḇ</span> — 'so these three men stopped answering Job' — šāḇat (to cease/stop; the Sabbath-rest verb applied to the friends' exhaustion of arguments). <span class='term'>kî hûʾ ṣaddîq bĕʿênāyw</span> — 'because he was righteous in his own eyes' — bĕʿênāyw = 'in his own eyes'; the narrator's framing of the friends' stopping point: they ceased because Job maintained his ṣaddîq status in his own eyes — not because they believed him, but because they could not break his self-assessment. The phrase ṣaddîq bĕʿênāyw will be reprised in Elihu's anger in v2.</p>",
    "2": "<p><span class='term'>wayyiḥar ʾap̄ ʾĔlîhû ben-ḇaraḵĕʾēl habbûzî</span> — 'the anger of Elihu son of Barachel the Buzite burned' — ḥārāh ʾap̄ (to be angry; the nostrils-burn idiom — ʾap̄ = both 'nose' and 'anger' because of the visible nostril-flaring of anger; used throughout from Gen 30:2 to Num 11:1). ʾēlîhû = 'He is my God' or 'My God is He'; Barachel = 'God blesses'; Bûzî = from Buz (Nahor's son in Gen 22:21, an Arabian location). <span class='term'>wayyiḥar ʾappô bĕʾîyôḇ ʿal-ṣaddĕqô nap̄šô mēʾĔlōhîm</span> — 'angry against Job for justifying himself rather than God' — nepeš (self/soul); ṣādaq in the pi'el = to declare righteous; Elihu is angry that Job justified himself at the expense of God's justice — but also (v3) angry at the friends for failing to answer.</p>",
    "3": "<p><span class='term'>wĕḇišĕlōšeṯ rēʿāyw ḥārāh ʾappô</span> — 'he was also angry with his three friends' — the double anger is structurally remarkable: Elihu is enraged both at Job's self-justification AND at the friends' inadequate theodicy. <span class='term'>ʿal ʾăšer lōʾ-māṣĕʾû maʿăneh wayyarĕšîʿû ʾeṯ-ʾîyôḇ</span> — 'because they had found no answer and yet condemned Job' — māṣāʾ maʿăneh (to find/discover an answer); rāšaʿ in the hip'il = to declare wicked/condemn; the friends condemned Job without an adequate theological basis for doing so. This is Elihu's charge against the friends: conviction without adequate argument.</p>",
    "4": "<p><span class='term'>wĕʾĔlîhû ḥikkāh ʾeṯ-ʾîyôḇ biddĕḇārîm</span> — 'Elihu had waited to speak with/about Job' — ḥikkāh (to wait for eagerly; the same root as tiqwāh's waiting; Ps 33:20 'our soul waits/ḥāḵāh for the LORD'); the technical meaning here is that Elihu waited in queue, holding back his words while the older men finished. <span class='term'>kî zĕqēnîm hēmmāh mimmennû lĕyāmîm</span> — 'because they were older than he was in days' — the cultural protocol of age-deference; Elihu has been waiting not from timidity but from respect for seniority, which makes his eventual anger more credible.</p>",
    "5": "<p><span class='term'>wayyarʾ ʾĔlîhû kî ʾên maʿăneh bĕp̄î šĕlōšeṯ hāʾănāšîm</span> — 'when Elihu saw that there was no answer in the mouth of the three men' — rāʾāh (to see, with understanding); ʾên maʿăneh bĕpî (there is no answer in the mouth); the three had not merely paused but had genuinely exhausted their argumentative resources. <span class='term'>wayyiḥar ʾappô</span> — 'his anger was aroused' — the second use of wayyiḥar ʾappô (vv2-5 use it three times for the three objects of his anger); the compressed triple use creates a sense of pent-up heat about to release.</p>",
    "6": "<p><span class='term'>ʾănî ṣāʿîr lĕyāmîm wĕʾatttem yĕšîšîm</span> — 'I am young in days, and you are very old' — ṣāʿîr (young/junior); yĕšîšîm (the most advanced elders, from yāšēš = to grow very old; used only here and 15:10; a super-aged plural). <span class='term'>ʿal-kēn zāḥaltî wāʾîrāʾ mēḥawwōṯ daʿtî ʾetḵem</span> — 'therefore I was afraid and held back from telling you my opinion' — zāḥal (to shrink back/withdraw; used in Deut 32:24 for a serpent-like shrinking; rare); ḥawwāh + daʿat = declaring/showing knowledge. Elihu explicitly narrates his process: age-deference overcoming the urgency of what he had to say.</p>",
    "7": "<p><span class='term'>ʾāmartî yāmîm yĕdabbĕrû</span> — 'I thought, let the aged speak' — the conventional wisdom protocol that age brings wisdom (cf. 12:12's same maxim, which Job both cites and subverts); Elihu has been operating by this protocol and finding it inadequate. <span class='term'>wĕrōḇ šānîm yôḏîʿû ḥāḵmāh</span> — 'and many years teach wisdom' — rōḇ šānîm (multitude of years); yôḏîʿû (make known/teach); the conventional claim Elihu is about to challenge in v8.</p>",
    "8": "<p><span class='term'>ʾāḵēn rûaḥ-hîʾ ḇĕʾĕnôš</span> — 'but truly, it is the Spirit in a person' — ʾāḵēn (truly/surely, a strong adversative contra the preceding maxim); rûaḥ (spirit/breath, the animating principle); bĕʾĕnôš (in man/humankind). <span class='term'>wĕnišmaṯ Šaddai tĕḇînēm</span> — 'and the breath of Shaddai gives understanding' — nišmāh (breath; used in Gen 2:7 for God's breath that animated Adam: 'the LORD God breathed into his nostrils the nišmaṯ ḥayyîm'); Šaddai (El Shaddai, the most common divine name in Job's poetry); tĕḇînēm (makes them understand; from bîn). The verse grounds human understanding not in accumulated experience (age) but in the divine-breath given at creation — a direct link between anthropology (creation) and epistemology. John 20:22's inbreathing of the Spirit ('receive the Holy Spirit') re-enacts this creational breath for the new creation community.</p>",
    "9": "<p><span class='term'>lō-rabbîm yaḥkāmû</span> — 'it is not the many/great ones who are wise' — rabbîm (many, or 'the great ones'); ḥāḵam (to be wise); the wisdom-egalitarianism of v8 has a direct corollary: greatness and seniority do not automatically confer wisdom. <span class='term'>ûzĕqēnîm yāḇînû mišpāṭ</span> — 'nor do the aged always understand what is right' — zĕqēnîm (elders/aged); yāḇîn (understand; the key Elihu verb from bîn); mišpāṭ (justice/right judgment). The verse decouples age and wisdom, seniority and judgment — a remarkable counter-cultural statement in an honor-culture that venerates elders.</p>",
    "10": "<p><span class='term'>lāḵēn ʾāmartî šimĕʿû-lî</span> — 'therefore I say: listen to me' — lāḵēn (therefore) draws the logical conclusion from vv8-9: since wisdom comes from divine breath rather than age, Elihu has as legitimate a claim to be heard as the elders. <span class='term'>ʾăḥawweh daʿtî ap̄-ʾānî</span> — 'I too will state what I know' — ḥawwāh (to declare/show; same root as v6 and v17); ap̄-ʾānî ('even I' — the emphatic first person singular that refuses to accept automatic disqualification by youth). The claim is grounded in the creation-breath of v8, not in presumption.</p>",
    "11": "<p><span class='term'>hēn ḥikkîṯî lĕdiḇrêḵem</span> — 'look, I waited for your words' — ḥikkîṯî (I waited; from ḥāḵāh, the verb of eager waiting used in v4); the formal acknowledgment that Elihu has fulfilled the protocol of waiting. <span class='term'>ʾăḇîn ʿaḏ-taḵlîyûn millîm</span> — 'I listened until you had finished your arguments' — ʾăḇîn (I was understanding/paying attention; from bîn in the imperfect used as a past narrative); taḵlîyûn (you completed; from kālāh = to finish/complete); the auditory attentiveness Elihu claims to have maintained throughout the dialogue.</p>",
    "12": "<p><span class='term'>wĕʿāḏêhem ʾeṯbônān</span> — 'and I listened carefully to all of you' — hitbônen (to direct one's understanding toward, to give careful attention; the hitpa'el of bîn expressing reflexive and intensive understanding — the same verb as 'staring at' in 30:20). <span class='term'>wĕhinnēh ʾên lĕʾîyôḇ mōḵîaḥ</span> — 'and not one of you has refuted Job' — mōḵîaḥ (one who argues/refutes; the hiph'il participle of yāḵaḥ — the forensic-argument root used throughout Job; 13:3,15; 16:21; 23:7); the charge against the three friends: they spoke at length but never actually engaged Job's argument at the forensic level.</p>",
    "13": "<p><span class='term'>pen-tōʾmĕrû māṣāʾnû ḥāḵmāh</span> — 'do not say: we have found wisdom' — ʾāmar + māṣāʾ ḥāḵmāh (to claim discovery of wisdom); Elihu warns the friends against the self-consoling claim that their failure to answer Job is actually a sign of superior wisdom. <span class='term'>ʾēl yiddĕp̄ennû lōʾ ʾîš</span> — 'let God deal with him, not us' — yiddĕp̄eh (from nādap̄ = to drive away/thrust aside; rare); the dismissive passing of Job's case back to God as an evasion of the friends' responsibility. Elihu refuses to allow this theological exit strategy.</p>",
    "14": "<p><span class='term'>wĕlō-ʿāraḵ ʾēlay millîm</span> — 'he has not directed his argument against me' — ʿārak (to arrange/order, the legal-brief word; cf. 13:18 'I have ordered/ʿāraktî my case'); Job has not targeted his argument at Elihu specifically. <span class='term'>wĕḇdibĕrêḵem lōʾ ʾăšîḇennû</span> — 'and I will not reply to him with your kind of arguments' — the formal distancing from the three friends' approach: Elihu commits in advance to a different argumentative strategy. The verse establishes Elihu as a genuinely independent voice, not merely a fourth iteration of the retributive framework.</p>",
    "15": "<p><span class='term'>ḥattû lōʾ-ʿānû ʿôd</span> — 'they are astonished, they say nothing more' — ḥāṯat (to be dismayed/shattered; the verb of complete psychological collapse under overwhelming evidence or divine presence; Josh 1:9; Isa 31:4); the three friends have been silenced not by persuasion but by the weight of Job's unanswered arguments. <span class='term'>nāśĕʿû mēhem millîm</span> — 'words have left them' — nāśāʾ (to carry away/lift up); millîm (words/arguments); the arguments have been carried away, leaving the friends empty-handed.</p>",
    "16": "<p><span class='term'>wĕhôḥaltî kî-lō yĕdabbĕrû</span> — 'I waited because they did not speak' — ḥûl/ḥîl (to wait/writhe in labor-pains; the word for the birthing-labor used in Ps 22:9-10 and Isa 26:17-18); Elihu's waiting is not passive but like labor contractions. <span class='term'>kî ʿāmĕḏû lō-ʿānû ʿôd</span> — 'they stood there and answered no more' — ʿāmaḏ (to stand/remain standing); the three friends standing speechless is a visual tableau of intellectual defeat.</p>",
    "17": "<p><span class='term'>ʾaʿăneh ʾap̄-ʾānî ḥelqî</span> — 'then I said: I too will give my answer, my portion' — ḥēleq (portion/allotment; the same word as the divine 'portion from above' in 31:2); Elihu's turn to speak is his appointed ḥēleq — his divinely allotted portion of the dialogue. <span class='term'>ʾăḥawweh daʿtî ʾānî</span> — 'I too will state what I know' — a slight variation of v10b; the repetition creates a rhetorical frame around the waiting-and-watching section (vv10-17) that preceded his actual speech.</p>",
    "18": "<p><span class='term'>kî māleʾtî millîm</span> — 'for I am full of words' — māleʾ (to be full/filled; the fullness-of-speech word); millîm (words). <span class='term'>hĕṣîqatnî rûaḥ ḇiṭnî</span> — 'the spirit within me urges me on' — hēṣîq (to press/constrain; from ṣûq = to press/squeeze; used in Jer 19:9 for siege-pressure); rûaḥ (spirit, picking up the rûaḥ of v8's creation-breath; Elihu's inner compulsion to speak is the action of the same Spirit that gives understanding); ḇeṭen (belly/interior, the deep inner self). The compulsion to speak from an inner spiritual pressure is exactly what the NT prophets describe (1 Cor 9:16 'necessity is laid upon me'; Acts 4:20 'we cannot but speak').</p>",
    "19": "<p><span class='term'>hinnēh-ḇiṭnî kĕyayin lō-yippāṯēaḥ</span> — 'my belly is like wine that has no outlet' — ḇeṭen (the inner vessel); yayyin (wine); pāṯaḥ (to open); the fermentation-pressure metaphor: wine sealed without a vent will burst the container. <span class='term'>kĕʾōḇôṯ ḥăḏāšîm yibbāqēaʿ</span> — 'like new wineskins about to burst' — ʾōḇ (wineskin/bellows; a skin bag); ḥăḏāšîm (new/fresh); bāqaʿ (to split/burst open). The new-wineskin image is used by Jesus in Matt 9:17 / Mark 2:22 / Luke 5:37-38 for the new wine of the kingdom that cannot be contained in old wineskins — the gospel's explosive new content demanding new forms. Elihu's metaphor prefigures the kind of pressure that the divine speech from the whirlwind will exert.</p>",
    "20": "<p><span class='term'>ʾăḏabbĕrāh wĕyirwaḥ lî</span> — 'I will speak and find relief' — rāwaḥ (to breathe/find relief; from rûaḥ = breath/spirit; the physical relief of releasing pent-up breath as metaphor for finally speaking what has been held back). <span class='term'>ʾep̄tāḥ śĕp̄āṯay wĕʾeʿĕneh</span> — 'I will open my lips and answer' — the opening of lips as the formal beginning of speech; pātaḥ (to open); the verse signals Elihu's transition from preamble to the actual content of his argument that begins in ch33.</p>",
    "21": "<p><span class='term'>ʾal-nāʾ ʾeśśāʾ p̄ĕnê-ʾîš</span> — 'I will not show partiality to any person' — nāśāʾ p̄ānîm (to lift the face/show favoritism; the judicial corruption idiom; Lev 19:15 prohibits it explicitly); Job has accused the friends of divine advocacy through partiality (13:8); Elihu renounces it in advance. <span class='term'>wĕʾel-ʾādām lō ʾăḵanneh</span> — 'nor will I give flattering titles to any man' — kinnāh (to give a title/honorific to; from kinnûy = nickname/epithet; rare). Elihu's commitment to titles-free, partiality-free speech sets up the authority of what follows — his argument stands on its merits, not on rhetorical deference.</p>",
    "22": "<p><span class='term'>kî lō yāḏaʿtî ʾăḵanneh</span> — 'for I do not know how to flatter' — the confession of incapacity for flattery as a mark of integrity; yāḏaʿ (to know how); ʾăḵanneh (to give honorific titles, from v21). <span class='term'>kimʿaṭ yiśśāʾēnî ʿōśenî</span> — 'if I did, my Maker would soon take me away' — kimʿaṭ (quickly/soon; the word of almost-immediacy); nāśāʾ (to carry away/remove); ʿōśenî (my Maker; from ʿāśāh = to make/do). The ground of Elihu's integrity is theological accountability: to flatter would be to court immediate divine removal. The chapter ends with the same divine Maker who gave the understanding-breath (v8) serving as the guarantor of honest speech.</p>"
  }
}

def main():
    c = load_comm('mkt-original', 'job')
    merge_comm(c, JOB3032)
    save_comm('mkt-original', 'job', c)
    count = sum(len(v) for v in JOB3032.values())
    print(f'job mkt-original: wrote {count} verses for ch 30–32')

if __name__ == '__main__':
    main()
